CREATE INDEX IF NOT EXISTS "appointment_holds_square_cof_checkout_order_id_idx" ON "appointment_holds" USING btree ("checkout_order_id","id") WHERE "appointment_holds"."payment_provider" = 'square' AND "appointment_holds"."card_on_file_status" IS NOT NULL AND "appointment_holds"."square_payment_link_id" IS NULL;--> statement-breakpoint
CREATE INDEX IF NOT EXISTS "checkout_orders_paid_square_appointment_not_booked_idx" ON "checkout_orders" USING btree ("paid_at","id","order_id") WHERE "checkout_orders"."status" = 'paid' AND "checkout_orders"."payment_provider" = 'square' AND "checkout_orders"."purpose" IN ('appointment_deposit', 'appointment_full', 'appointment_custom_partial') AND "checkout_orders"."calendar_finalization_status" NOT IN ('not_required', 'booked', 'manual_rebooked');
